import { TextStyle } from 'react-native';

export const typography = {
  headline: {
    fontSize: 34,
    lineHeight: 40,
    fontWeight: '800',
  } as TextStyle,
  title: {
    fontSize: 22,
    lineHeight: 28,
    fontWeight: '700',
  } as TextStyle,
  body: {
    fontSize: 16,
    lineHeight: 24,
    fontWeight: '400',
  } as TextStyle,
  caption: {
    fontSize: 13,
    lineHeight: 18,
    fontWeight: '400',
  } as TextStyle,
  label: {
    fontSize: 14,
    lineHeight: 20,
    fontWeight: '700',
  } as TextStyle,
} as const;

export const spacing = {
  xs: 4,
  sm: 8,
  md: 12,
  lg: 16,
  xl: 20,
  xxl: 24,
  xxxl: 32,
} as const;

import { ViewStyle } from 'react-native';

export const elevation = {
  level0: {
    elevation: 0,
    shadowColor: 'transparent',
    shadowOffset: { width: 0, height: 0 },
    shadowOpacity: 0,
    shadowRadius: 0,
  } as ViewStyle,
  level1: {
    elevation: 1,
    shadowColor: '#211c16',
    shadowOffset: { width: 0, height: 1 },
    shadowOpacity: 0.05,
    shadowRadius: 3,
  } as ViewStyle,
  level2: {
    elevation: 3,
    shadowColor: '#211c16',
    shadowOffset: { width: 0, height: 2 },
    shadowOpacity: 0.08,
    shadowRadius: 6,
  } as ViewStyle,
  level3: {
    elevation: 6,
    shadowColor: '#211c16',
    shadowOffset: { width: 0, height: 4 },
    shadowOpacity: 0.12,
    shadowRadius: 12,
  } as ViewStyle,
} as const;

import { ReduceMotion, WithSpringConfig } from 'react-native-reanimated';

const base = { reduceMotion: ReduceMotion.System } as const;

export const motion = {
  snappy: {
    ...base,
    damping: 20,
    stiffness: 300,
    mass: 0.8,
  } satisfies WithSpringConfig,
  gentle: {
    ...base,
    damping: 20,
    stiffness: 120,
    mass: 1,
  } satisfies WithSpringConfig,
  bouncy: {
    ...base,
    damping: 12,
    stiffness: 180,
    mass: 0.8,
  } satisfies WithSpringConfig,
  quick: {
    ...base,
    damping: 26,
    stiffness: 400,
    mass: 0.6,
  } satisfies WithSpringConfig,
} as const;

