import React, { useState } from 'react';
import { StyleSheet, TextInput, View } from 'react-native';
import Animated, {
  interpolateColor,
  useAnimatedStyle,
  useSharedValue,
  withSpring,
  withTiming,
} from 'react-native-reanimated';

import { colors } from '../theme/colors';
import { motion } from '../theme/motion';
import { AnimatedPressable } from './AnimatedPressable';

interface SearchBarProps {
  value: string;
  onChangeText: (text: string) => void;
  placeholder?: string;
}

export function SearchBar({ value, onChangeText, placeholder = 'Search...' }: SearchBarProps) {
  const focused = useSharedValue(0);
  const [isFocused, setIsFocused] = useState(false);

  const borderStyle = useAnimatedStyle(() => ({
    borderColor: interpolateColor(
      focused.value,
      [0, 1],
      [colors.line, colors.brand]
    ),
  }));

  const clearOpacity = useAnimatedStyle(() => ({
    opacity: withTiming(value.length > 0 ? 1 : 0, { duration: 150 }),
  }));

  return (
    <Animated.View
      style={[styles.container, borderStyle]}
      accessibilityRole="search"
    >
      <Animated.Text style={styles.icon}>
        {'\u{1F50D}'}
      </Animated.Text>
      <TextInput
        style={styles.input}
        value={value}
        onChangeText={onChangeText}
        placeholder={placeholder}
        placeholderTextColor={colors.mutedInk}
        onFocus={() => {
          focused.value = withSpring(1, motion.snappy);
          setIsFocused(true);
        }}
        onBlur={() => {
          focused.value = withSpring(0, motion.snappy);
          setIsFocused(false);
        }}
        accessibilityLabel={placeholder}
      />
      {value.length > 0 && (
        <Animated.View style={clearOpacity}>
          <AnimatedPressable
            onPress={() => onChangeText('')}
            accessibilityLabel="Clear search"
            accessibilityRole="button"
          >
            <View style={styles.clearButton}>
              <Animated.Text style={styles.clearText}>X</Animated.Text>
            </View>
          </AnimatedPressable>
        </Animated.View>
      )}
    </Animated.View>
  );
}

const styles = StyleSheet.create({
  container: {
    flexDirection: 'row',
    alignItems: 'center',
    borderRadius: 16,
    borderWidth: 1.5,
    backgroundColor: colors.canvas,
    paddingHorizontal: 14,
    gap: 8,
  },
  icon: {
    fontSize: 16,
  },
  input: {
    flex: 1,
    paddingVertical: 12,
    color: colors.ink,
    fontSize: 16,
  },
  clearButton: {
    width: 24,
    height: 24,
    borderRadius: 12,
    backgroundColor: colors.line,
    alignItems: 'center',
    justifyContent: 'center',
  },
  clearText: {
    color: colors.mutedInk,
    fontSize: 12,
    fontWeight: '700',
  },
});

