            mass: 0.8,
          }),
        },
      ],
    };
  });

  return <Animated.View style={[styles.pill, animatedStyle]} />;
}

const styles = StyleSheet.create({
  pill: {
    position: 'absolute',
    top: 8,
    left: 0,
    width: 64,
    height: 32,
    borderRadius: 16,
    backgroundColor: colors.brandLight,
  },
});

