    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
  },
  meta: {
    ...typography.caption,
    color: colors.mutedInk,
  },
  total: {
    ...typography.label,
    color: colors.brandDeep,
  },
});

