import React from 'react';
import { StyleSheet, Text, View } from 'react-native';

import { AnimatedPressable } from '../../../components/AnimatedPressable';
import { Cart } from '../../../domain/models';
import { formatCurrency, formatDate } from '../../../lib/format';
import { colors } from '../../../theme/colors';
import { typography } from '../../../theme/typography';

interface CompletedCartCardProps {
  cart: Cart;
  total: number;
  onPress: () => void;
}

export const CompletedCartCard = React.memo(function CompletedCartCard({
  cart,
  total,
  onPress,
}: CompletedCartCardProps) {
  const budgetDiff = total - cart.budget;

  return (
    <AnimatedPressable
      onPress={onPress}
      accessibilityRole="button"
      accessibilityLabel={`${cart.name}, completed ${formatDate(cart.completedAt)}, total ${formatCurrency(total)}`}
