  eyebrow: {
    ...typography.eyebrow,
    color: colors.brandDeep,
  },
  greeting: {
    ...typography.headline,
    color: colors.ink,
  },
  summary: {
    ...typography.body,
    color: colors.mutedInk,
    fontSize: 15,
  },
});

