import React from 'react';
import { StyleSheet, Text, View } from 'react-native';

import { AnimatedPressable } from '../../../components/AnimatedPressable';
import { Cart } from '../../../domain/models';
import { formatCurrency, formatDate } from '../../../lib/format';
import { colors } from '../../../theme/colors';
import { typography } from '../../../theme/typography';

interface CompletedCartCardProps {
  cart: Cart;
  total: number;
  onPress: () => void;
}

export const CompletedCartCard = React.memo(function CompletedCartCard({
  cart,
  total,
  onPress,
}: CompletedCartCardProps) {
  const budgetDiff = total - cart.budget;

  return (
    <AnimatedPressable
      onPress={onPress}
      accessibilityRole="button"
      accessibilityLabel={`${cart.name}, completed ${formatDate(cart.completedAt)}, total ${formatCurrency(total)}`}
    >
      <View style={styles.card}>
        <View style={styles.header}>
          <Text style={styles.name}>{cart.name}</Text>
          <Text style={styles.total}>{formatCurrency(total)}</Text>
        </View>
        <View style={styles.footer}>
          <Text style={styles.date}>{formatDate(cart.completedAt)}</Text>
          {budgetDiff !== 0 && (
            <Text style={[styles.budgetDiff, budgetDiff > 0 && styles.overBudget]}>
              {budgetDiff > 0 ? '+' : ''}{formatCurrency(budgetDiff)} vs budget
            </Text>
          )}
        </View>
      </View>
    </AnimatedPressable>
  );
});

const styles = StyleSheet.create({
  card: {
    borderRadius: 20,
    backgroundColor: colors.surface,
    padding: 18,
    borderWidth: 1,
    borderColor: colors.divider,
    gap: 8,
  },
