    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
  },
  name: {
    ...typography.label,
    color: colors.ink,
    fontSize: 16,
  },
  total: {
    ...typography.label,
    color: colors.brandDeep,
  },
  footer: {
    flexDirection: 'row',
    justifyContent: 'space-between',
    alignItems: 'center',
  },
  date: {
    ...typography.caption,
    color: colors.subtleInk,
  },
  budgetDiff: {
    ...typography.caption,
    color: colors.success,
    fontFamily: 'SourceSans3-Bold',
  },
  overBudget: {
    color: colors.danger,
  },
});

