              <View style={styles.markButton}>
                <Text style={styles.markButtonText}>Done</Text>
              </View>
            </AnimatedPressable>
          )}
        </Animated.View>
      </GestureDetector>
    </View>
  );
});

const styles = StyleSheet.create({
