    paddingHorizontal: 18,
    backgroundColor: colors.surface,
  },
  info: {
    flex: 1,
    gap: 4,
  },
  name: {
    ...typography.label,
    color: colors.ink,
    fontSize: 15,
  },
  strikethrough: {
    textDecorationLine: 'line-through',
    color: colors.mutedInk,
  },
  detail: {
    ...typography.caption,
    color: colors.mutedInk,
  },
  markButton: {
    borderRadius: 14,
    borderWidth: 1,
    borderColor: colors.success,
    paddingHorizontal: 12,
    paddingVertical: 8,
  },
  markButtonText: {
    color: colors.success,
    fontWeight: '700',
    fontSize: 13,
  },
});

