import React from 'react';
import { ScrollView, StyleSheet, Text, View } from 'react-native';
import Animated, { FadeInUp } from 'react-native-reanimated';

import { computeCartTotal } from '../../domain/models';
import { formatCurrency, formatDate } from '../../lib/format';
import { useAppStore } from '../../state/useAppStore';
import { colors } from '../../theme/colors';
import { stagger } from '../../theme/motion';
import { spacing } from '../../theme/spacing';
import { typography } from '../../theme/typography';

export function HistoryScreen() {
  const appState = useAppStore(state => state.appState);

  if (!appState) {
    return null;
  }

  const completed = appState.vault.carts.filter(cart => cart.status === 'completed' && !cart.isDeleted);

  return (
    <ScrollView style={styles.screen} contentContainerStyle={styles.content}>
      <Text style={styles.title}>History</Text>
      <Text style={styles.subtitle}>Completed carts and the totals they closed with.</Text>

      {completed.length ? (
        completed.map((cart, index) => (
          <Animated.View key={cart.id} entering={FadeInUp.delay(stagger(index))}>
            <View style={styles.card}>
              <Text style={styles.cardTitle}>{cart.name}</Text>
              <Text style={styles.cardCopy}>Completed {formatDate(cart.completedAt)}</Text>
              <Text style={styles.total}>{formatCurrency(computeCartTotal(appState.vault, cart))}</Text>
            </View>
          </Animated.View>
        ))
      ) : (
        <View style={styles.card}>
          <Text style={styles.cardTitle}>No history yet</Text>
          <Text style={styles.cardCopy}>Complete a shopping trip to populate this screen.</Text>
        </View>
      )}
    </ScrollView>
  );
}

const styles = StyleSheet.create({
  screen: {
    flex: 1,
    backgroundColor: colors.canvas,
  },
  content: {
    padding: spacing.page,
    gap: 14,
  },
  title: {
    ...typography.headline,
    color: colors.ink,
  },
  subtitle: {
    ...typography.body,
    color: colors.mutedInk,
  },
  card: {
    borderRadius: 20,
    backgroundColor: colors.surface,
    borderWidth: 1,
    borderColor: colors.divider,
    padding: 16,
    gap: 6,
  },
  cardTitle: {
    ...typography.subtitle,
    color: colors.ink,
  },
  cardCopy: {
    ...typography.caption,
    color: colors.subtleInk,
  },
  total: {
    ...typography.numericDisplay,
    color: colors.brandDeep,
    fontSize: 20,
    marginTop: 6,
  },
});

